class Solution {
    public String smallestNumber(String pattern) {
        int n = pattern.length();
        char[] num = new char[n + 1];
        for (int i = 0; i <= n; i++) {
            num[i] = (char) ('1' + i);
        }
        for (int i = 0; i < n; i++) {
            if (pattern.charAt(i) == 'D') {
                int j = i;
                while (i < n && pattern.charAt(i) == 'D') {
                    i++;
                }
                reverse(num, j, i);
            }
        }
        return new String(num);
    }

    private void reverse(char[] num, int i, int j) {
        while (i < j) {
            char temp = num[i];
            num[i] = num[j];
            num[j] = temp;
            i++;
            j--;
        }
    }
}
